SELECT date, name
FROM data_collections
ORDER BY date DESC;

SELECT name, AVG(age) AS average_age
FROM data_collections
GROUP BY name;

SELECT name
FROM locations
ORDER BY name ASC;

SELECT name
FROM locations
ORDER BY name;

SELECT name, AVG(age) AS average_age, COUNT(*) AS collection_count
FROM data_collections
WHERE name = 'Location1';
